# Category: race_condition

class BankAccount:
    def __init__(self, initial_balance):
        self.balance = initial_balance

    def deposit(self, amount):
        self.balance += amount

    def withdraw(self, amount):
        if amount > self.balance:
            print("Insufficient funds")
        else:
            self.balance -= amount


def update_account(account, transaction_type, amount):
    if transaction_type == "deposit":
        account.deposit(amount)
    elif transaction_type == "withdrawal":
        account.withdraw(amount)


# Create a bank account with initial balance
account = BankAccount(1000)

# Process transactions
update_account(account, "deposit", 500)
print("Balance:", account.balance)  # Output: Balance: 1500.0

update_account(account, "withdrawal", 200)
print("Balance:", account.balance)  # Output: Balance: 1300.0

update_account(account, "withdrawal", 1200)
print("Balance:", account.balance)  # Output: Insufficient funds